import anthropic
import re

client = anthropic.Anthropic()

# Simulated tools

def search(query: str) -> str:
    db = {
        "population of tokyo": "Tokyo's population is approximately 13.96 million in the city proper (2023).",
        "population of delhi": "Delhi's population is approximately 32.9 million in the metropolitan area (2023).",
        "population of new york": "New York City's population is approximately 8.3 million (2023).",
    }
    for k, v in db.items():
        if all(w in query.lower() for w in k.split()):
            return v
    return "No result found for query: " + query


def calc(expr: str) -> str:
    try:
        safe = re.sub(r"[^0-9+\-*/().\s]", "", expr)
        return str(eval(safe))  # noqa: S307 — demo only
    except Exception as e:
        return f"Calculation error: {e}"


def format_observation(tool: str, result: str, max_chars: int = 300) -> str:
    """Format a tool result as an observation, truncating if needed."""
    if not result or result.strip() == "":
        return f"Observation: {tool} returned no output. Try rephrasing your query."
    truncated = result[:max_chars]
    if len(result) > max_chars:
        truncated += " [truncated]"
    return f"Observation: {truncated}"


def dispatch(action_text: str) -> str:
    m = re.match(r"(search|calc)\[(.+?)\]", action_text.strip(), re.IGNORECASE)
    if not m:
        return "Observation: Unrecognised action. Use search[query] or calc[expression]."
    tool, arg = m.group(1).lower(), m.group(2)
    result = search(arg) if tool == "search" else calc(arg)
    return format_observation(tool, result)


SYSTEM = (
    "Solve the question by alternating Thought / Action / Observation steps.\n"
    "Actions: search[query] or calc[expression].\n"
    "End with: Final Answer: <value>"
)


def react(question: str, max_steps: int = 8) -> str:
    messages = [{"role": "user", "content": question}]
    for _ in range(max_steps):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=300,
            temperature=0.0,
            system=SYSTEM,
            messages=messages,
            stop_sequences=["Observation:"],
        )
        model_turn = resp.content[0].text.strip()
        messages.append({"role": "assistant", "content": model_turn})
        print(f"Model: {model_turn}")

        if "Final Answer:" in model_turn:
            m = re.search(r"Final Answer:\s*(.+)", model_turn)
            return m.group(1).strip() if m else model_turn

        action_match = re.search(r"Action:\s*(.+)", model_turn)
        if not action_match:
            break

        observation = dispatch(action_match.group(1))
        print(f"Env:   {observation}")
        messages.append({"role": "user", "content": observation})

    return "[no final answer reached]"


result = react("How many more people live in Delhi than in New York City?")
print(f"\nFinal: {result}")

def safe_observation(tool_fn, arg: str, tool_name: str) -> str:
    """
    Wrap any tool call so that exceptions produce a well-formed
    error observation instead of crashing the loop.
    """
    try:
        result = tool_fn(arg)
        if not result or result.strip() == "":
            raise ValueError("empty result")
        return f"Observation: {result[:300]}"
    except Exception as e:
        return (
            f"Observation: {tool_name} failed with error '{e}'. "
            f"Consider a different query or approach."
        )


# Example: tool that raises on unknown input
def strict_search(query: str) -> str:
    data = {"capital of france": "Paris"}
    if query.lower() not in data:
        raise KeyError(f"'{query}' not in knowledge base")
    return data[query.lower()]


# Safe wrapping — loop can continue even after tool failure
print(safe_observation(strict_search, "capital of france", "search"))
print(safe_observation(strict_search, "capital of mars",   "search"))

import anthropic, json, re, time
from typing import Any

client = anthropic.Anthropic()

# ---------- Tool implementations ----------
def web_search(query: str) -> dict:
    """Stubbed — real impl would call a search API."""
    return {
        "results": [
            {"title": "UMAP docs", "snippet": "UMAP is a manifold learning technique..."},
            {"title": "arxiv 1802.03426", "snippet": "UMAP: Uniform Manifold Approximation..."},
        ]
    }

def run_python(code: str) -> dict:
    """Stubbed code executor."""
    return {"stdout": "array([0.1, 0.9, 0.5])", "stderr": ""}

# ---------- Observation formatter ----------
def format_observation(tool: str, raw: Any, max_chars: int = 400) -> str:
    """
    Convert any tool output to a well-formed observation string.
    Rules:
      1. Label with 'Observation:'
      2. Flatten structured data to prose
      3. Truncate long strings with [truncated] marker
      4. Convert exceptions to helpful error messages
    """
    if isinstance(raw, Exception):
        return f"Observation: {tool} raised {type(raw).__name__}: {raw}. Consider alternative approach."

    if isinstance(raw, dict):
        # Flatten common patterns
        if "error" in raw:
            return f"Observation: {tool} returned error — {raw['error']}."
        if "results" in raw and isinstance(raw["results"], list):
            snippets = "; ".join(
                f"{r.get('title','?')}: {r.get('snippet','?')[:80]}"
                for r in raw["results"][:3]
            )
            text = f"Search returned {len(raw['results'])} results: {snippets}"
        elif "stdout" in raw:
            text = raw["stdout"] or "(no output)"
            if raw.get("stderr"):
                text += f" | stderr: {raw['stderr'][:100]}"
        else:
            text = json.dumps(raw)[:max_chars]
    elif isinstance(raw, list):
        text = "; ".join(str(x) for x in raw[:5])
    else:
        text = str(raw)

    if len(text) > max_chars:
        text = text[:max_chars] + " [truncated]"
    return f"Observation: {text}"

# ---------- Dispatcher ----------
TOOLS = {"web_search": web_search, "run_python": run_python}

def dispatch(action_text: str) -> str:
    m = re.match(r"(\w+)\[(.+?)\]$", action_text.strip(), re.DOTALL)
    if not m:
        return "Observation: Unrecognised action format. Use tool_name[argument]."
    tool_name, arg = m.group(1), m.group(2)
    if tool_name not in TOOLS:
        return f"Observation: Unknown tool '{tool_name}'. Available: {list(TOOLS)}."
    try:
        result = TOOLS[tool_name](arg)
    except Exception as e:
        result = e
    return format_observation(tool_name, result)

# ---------- ReAct loop ----------
SYSTEM = (
    "You are a research agent. Solve tasks step by step using:\n"
    "Thought: <reasoning>\n"
    "Action: tool_name[argument]\n"
    "Observation: (provided by environment)\n"
    "...repeat until...\n"
    "Final Answer: <answer>"
)

def react(question: str, max_steps: int = 8) -> str:
    messages = [{"role": "user", "content": question}]
    for step in range(max_steps):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            temperature=0.0,
            system=SYSTEM,
            messages=messages,
            stop_sequences=["Observation:"],
        )
        turn = resp.content[0].text.strip()
        messages.append({"role": "assistant", "content": turn})

        if "Final Answer:" in turn:
            m = re.search(r"Final Answer:\s*(.+)", turn, re.DOTALL)
            return m.group(1).strip() if m else turn

        action_m = re.search(r"Action:\s*(.+)", turn)
        if not action_m:
            break

        obs = dispatch(action_m.group(1))
        messages.append({"role": "user", "content": obs})
        time.sleep(0.2)  # rate-limit courtesy pause

    return "[loop ended without final answer]"

answer = react("What is UMAP used for in machine learning?")
print("Answer:", answer)
